// // This module counts down on each negative edge of clk and resets to zero when the reset signal is low.
module binary_counter(
	input clk,
	input reset,
	output reg [3:0] count);

always @(posedge clk or posedge reset)
	if (reset)
		count <= 4'b0000;
	else
		count <= count + 1;

endmodule
